      starterCode: "package com.workshop.repo;\n\nimport java.util.Optional;\n\nclass User {\n    long id;\n    String name;\n    User(long id, String name) { this.id = id; this.name = name; }\n}\n\ninterface UserRepository {\n    User save(User user);\n    Optional<User> findById(long id);\n}\n\nclass UserService {\n\n    // TODO: 声明一个 UserRepository 类型的 final 字段，命名为 repository\n\n    // TODO: 构造函数接收 UserRepository repository，把它存进字段（依赖注入）\n    public UserService() {\n    }\n\n    // 业务：注册一个用户。校验属于业务逻辑，留在 Service 里。\n    public User register(long id, String name) {\n        if (name == null || name.isBlank()) {\n            throw new IllegalArgumentException(\"name required\");\n        }\n        User user = new User(id, name);\n        // TODO: 通过 repository.save(...) 持久化，并返回结果\n        return null;\n    }\n}\n",
